SELECT id, order_no, registration_id, patient_id, patient_name, (SELECT p.gender FROM clinic_patient p WHERE p.id = patient_id AND p.deleted = 0 LIMIT 1) AS gender, (SELECT p.age FROM clinic_patient p WHERE p.id = patient_id AND p.deleted = 0 LIMIT 1) AS age, (SELECT p.phone FROM clinic_patient p WHERE p.id = patient_id AND p.deleted = 0 LIMIT 1) AS phone, charge_type, department_name, doctor_name, receivable_amount, discount_amount, paid_amount, refund_amount, pay_method, refund_method, status, cashier, paid_at, refunded_at, remark, created_at, updated_at, deleted FROM clinic_charge_order WHERE deleted = 0
AND (order_no LIKE CONCAT('%', #{keyword}, '%') OR patient_name LIKE CONCAT('%', #{keyword}, '%') OR charge_type LIKE CONCAT('%', #{keyword}, '%') OR status LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

SELECT id, order_no, registration_id, patient_id, patient_name, (SELECT p.gender FROM clinic_patient p WHERE p.id = patient_id AND p.deleted = 0 LIMIT 1) AS gender, (SELECT p.age FROM clinic_patient p WHERE p.id = patient_id AND p.deleted = 0 LIMIT 1) AS age, (SELECT p.phone FROM clinic_patient p WHERE p.id = patient_id AND p.deleted = 0 LIMIT 1) AS phone, charge_type, department_name, doctor_name, receivable_amount, discount_amount, paid_amount, refund_amount, pay_method, refund_method, status, cashier, paid_at, refunded_at, remark, created_at, updated_at, deleted FROM clinic_charge_order WHERE deleted = 0 AND charge_type = #{chargeType}
AND (order_no LIKE CONCAT('%', #{keyword}, '%') OR patient_name LIKE CONCAT('%', #{keyword}, '%') OR status LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

